const _arrow_trap = {title: "Arrow Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-arrow_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Arrow Trap</th></tr><tr><th id="trap-arrow_trap-arrow-trap-haunt-type">Type</th><td headers="trap-arrow_trap-arrow-trap-haunt-type">mechanical</td><th id="trap-arrow_trap-arrow-trap-haunt-cr">CR</th><td headers="trap-arrow_trap-arrow-trap-haunt-cr">1</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-arrow_trap-arrow-trap-haunt-trigger">Trigger</th><td headers="trap-arrow_trap-arrow-trap-haunt-trigger">touch</td><th id="trap-arrow_trap-arrow-trap-haunt-reset">Reset</th><td headers="trap-arrow_trap-arrow-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +15 ranged (1d8+1/&times;3)</td></tr></tbody></table></ScrollContainer></div></>};
const _bear_trap = {title: "Bear Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 184</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-bear_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Bear Trap</th></tr><tr><th id="trap-bear_trap-bear-trap-haunt-type">Type</th><td headers="trap-bear_trap-bear-trap-haunt-type">mechanical</td><th id="trap-bear_trap-bear-trap-haunt-cr">CR</th><td headers="trap-bear_trap-bear-trap-haunt-cr">1</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>15</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-bear_trap-bear-trap-haunt-trigger">Trigger</th><td headers="trap-bear_trap-bear-trap-haunt-trigger">location</td><th id="trap-bear_trap-bear-trap-haunt-reset">Reset</th><td headers="trap-bear_trap-bear-trap-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +10 melee (2d6+3); sharp jaws spring shut around the creature's ankle and halve the creature's base speed (or hold the creature immobile if the trap is attached to a solid object); the creature can escape with a DC 20 Disable Device check, DC 22 Escape Artist check, or DC 26 Strength check</td></tr></tbody></table></ScrollContainer></div></>};
const _breakaway_vine = {title: "Breakaway Vine", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 172</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-breakaway_vine--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Breakaway Vine</th></tr><tr><th id="trap-breakaway_vine-breakaway-vine-haunt-type">Type</th><td headers="trap-breakaway_vine-breakaway-vine-haunt-type">mechanical</td><th id="trap-breakaway_vine-breakaway-vine-haunt-cr">CR</th><td headers="trap-breakaway_vine-breakaway-vine-haunt-cr">1</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests, jungles, or swamps</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-breakaway_vine-breakaway-vine-haunt-trigger">Trigger</th><td headers="trap-breakaway_vine-breakaway-vine-haunt-trigger">touch (timed)</td><th id="trap-breakaway_vine-breakaway-vine-haunt-reset">Reset</th><td headers="trap-breakaway_vine-breakaway-vine-haunt-reset">repair</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A breakaway vine has been sabotaged so that it snaps not long after someone begins using it to climb. A breakaway vine trap can be crafted from a length of rope as well, but this ruins the rope for other uses. When a Small or larger creature climbs a breakaway vine, the vine snaps just before the creature reaches the top of the climb. A creature can grab a handhold and avoid the resulting fall with a successful DC 20 Reflex save. This breakaway vine assumes a 20-foot fall for 2d6 points of damage; longer falls increase the CR of the breakaway vine by 1 per additional 20 feet.</td></tr></tbody></table></ScrollContainer></div></>};
const _musk_shower = {title: "Musk Shower", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 172</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-musk_shower--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Musk Shower</th></tr><tr><th id="trap-musk_shower-musk-shower-haunt-type">Type</th><td headers="trap-musk_shower-musk-shower-haunt-type">mechanical</td><th id="trap-musk_shower-musk-shower-haunt-cr">CR</th><td headers="trap-musk_shower-musk-shower-haunt-cr">1</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-musk_shower-musk-shower-haunt-trigger">Trigger</th><td headers="trap-musk_shower-musk-shower-haunt-trigger">location</td><th id="trap-musk_shower-musk-shower-haunt-reset">Reset</th><td headers="trap-musk_shower-musk-shower-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Effect This trap hides a jury-rigged container of absorbent debris that has been soaked in the musk of prey animals. When a creature enters a square trapped with a musk shower, the trap makes a +10 melee touch attack against the creature. On a hit, the musk shower deals no damage but douses the target in its strong scent. Creatures with <Link to="/umr/scent">scent</Link> double the range at which they can smell a doused creature for 1 week or until the musk is washed off with alcohol or another solvent. Creatures tracking the doused creature by smell gain a +10 bonus on Perception and Survival checks to track that target.</td></tr></tbody></table></ScrollContainer></div></>};
const _pit_trap = {title: "Pit Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-pit_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Pit Trap</th></tr><tr><th id="trap-pit_trap-pit-trap-haunt-type">Type</th><td headers="trap-pit_trap-pit-trap-haunt-type">mechanical</td><th id="trap-pit_trap-pit-trap-haunt-cr">CR</th><td headers="trap-pit_trap-pit-trap-haunt-cr">1</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-pit_trap-pit-trap-haunt-trigger">Trigger</th><td headers="trap-pit_trap-pit-trap-haunt-trigger">location</td><th id="trap-pit_trap-pit-trap-haunt-reset">Reset</th><td headers="trap-pit_trap-pit-trap-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> 20-ft.-deep pit (2d6 falling damage); DC 20 Reflex avoids; multiple targets (all targets in a 10-ft.-square area)</td></tr></tbody></table></ScrollContainer></div></>};
const _poisoned_dart_trap = {title: "Poisoned Dart Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-poisoned_dart_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Poisoned Dart Trap</th></tr><tr><th id="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-type">Type</th><td headers="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-type">mechanical</td><th id="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-cr">CR</th><td headers="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-cr">1</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-trigger">Trigger</th><td headers="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-trigger">touch</td><th id="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-reset">Reset</th><td headers="trap-poisoned_dart_trap-poisoned-dart-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +10 ranged (1d3 plus <Link to="/eq-poison/greenblood_oil">greenblood oil</Link>)</td></tr></tbody></table></ScrollContainer></div></>};
const _spring_snare = {title: "Spring Snare", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 172</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-spring_snare--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Spring Snare</th></tr><tr><th id="trap-spring_snare-spring-snare-haunt-type">Type</th><td headers="trap-spring_snare-spring-snare-haunt-type">mechanical</td><th id="trap-spring_snare-spring-snare-haunt-cr">CR</th><td headers="trap-spring_snare-spring-snare-haunt-cr">1</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests, jungles, or swamps</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>25</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>15</td></tr><tr><th id="trap-spring_snare-spring-snare-haunt-trigger">Trigger</th><td headers="trap-spring_snare-spring-snare-haunt-trigger">location</td><th id="trap-spring_snare-spring-snare-haunt-reset">Reset</th><td headers="trap-spring_snare-spring-snare-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A spring snare consists of a strong sapling that's been bent down with a noose affixed to the end. When a creature enters a square trapped by a spring snare, the noose attempts to snare the triggering creature with a +15 on its combat maneuver check to grapple. If it succeeds, the tree snaps upright and flings the target into the air for 1d6 damage. The creature then remains suspended 10 feet off the ground until it breaks the grapple.</td></tr></tbody></table></ScrollContainer></div></>};
const _swinging_axe_trap = {title: "Swinging Axe Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-swinging_axe_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Swinging Axe Trap</th></tr><tr><th id="trap-swinging_axe_trap-swinging-axe-trap-haunt-type">Type</th><td headers="trap-swinging_axe_trap-swinging-axe-trap-haunt-type">mechanical</td><th id="trap-swinging_axe_trap-swinging-axe-trap-haunt-cr">CR</th><td headers="trap-swinging_axe_trap-swinging-axe-trap-haunt-cr">1</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-swinging_axe_trap-swinging-axe-trap-haunt-trigger">Trigger</th><td headers="trap-swinging_axe_trap-swinging-axe-trap-haunt-trigger">location</td><th id="trap-swinging_axe_trap-swinging-axe-trap-haunt-reset">Reset</th><td headers="trap-swinging_axe_trap-swinging-axe-trap-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +10 melee (1d8+1/&times;3); multiple targets (all targets in a 10-ft. line)</td></tr></tbody></table></ScrollContainer></div></>};
const _swinging_log = {title: "Swinging Log", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 172</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-swinging_log--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Swinging Log</th></tr><tr><th id="trap-swinging_log-swinging-log-haunt-type">Type</th><td headers="trap-swinging_log-swinging-log-haunt-type">mechanical</td><th id="trap-swinging_log-swinging-log-haunt-cr">CR</th><td headers="trap-swinging_log-swinging-log-haunt-cr">1</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests or jungles</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>12</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>12</td></tr><tr><th id="trap-swinging_log-swinging-log-haunt-trigger">Trigger</th><td headers="trap-swinging_log-swinging-log-haunt-trigger">location</td><th id="trap-swinging_log-swinging-log-haunt-reset">Reset</th><td headers="trap-swinging_log-swinging-log-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A large, heavy log is suspended in the canopy of a forest or jungle and attached to a trip line. When a creature passes through a 5-foot-square that's been trapped by this trip line, the log swings down and makes a melee attack with a +5 bonus (1d6+5 points of bludgeoning damage). A creature damaged by this log must succeed at a DC 15 Reflex save to avoid being knocked prone. Affixing a number of sharpened sticks to the log adds an additional 2d6 points of piercing damage and increases its CR by 1.</td></tr></tbody></table></ScrollContainer></div></>};
const _tar_snare = {title: "Tar Snare", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 172</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-tar_snare--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Tar Snare</th></tr><tr><th id="trap-tar_snare-tar-snare-haunt-type">Type</th><td headers="trap-tar_snare-tar-snare-haunt-type">mechanical</td><th id="trap-tar_snare-tar-snare-haunt-cr">CR</th><td headers="trap-tar_snare-tar-snare-haunt-cr">1</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any with tar pits or mud</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-tar_snare-tar-snare-haunt-trigger">Trigger</th><td headers="trap-tar_snare-tar-snare-haunt-trigger">location</td><th id="trap-tar_snare-tar-snare-haunt-reset">Reset</th><td headers="trap-tar_snare-tar-snare-haunt-reset">automatic</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A tar snare consists of a shallow trench filled with tar or sticky mud that is then covered with a layer of debris to disguise its presence. When a creature steps into a square trapped with a tar snare, the trap makes an attempt to grapple it with a +10 bonus on the combat maneuver check. Sharp sticks can be added to the pit as well-this increases the CR of the trap by 1 and affects a creature grappled by the trap as if it had walked on <Link to="/eq-misc/caltrops">caltrops</Link>.</td></tr></tbody></table></ScrollContainer></div></>};
const _burning_hands_trap = {title: "Burning Hands Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-burning_hands_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Burning Hands Trap</th></tr><tr><th id="trap-burning_hands_trap-burning-hands-trap-haunt-type">Type</th><td headers="trap-burning_hands_trap-burning-hands-trap-haunt-type">magic</td><th id="trap-burning_hands_trap-burning-hands-trap-haunt-cr">CR</th><td headers="trap-burning_hands_trap-burning-hands-trap-haunt-cr">2</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>26</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>26</td></tr><tr><th id="trap-burning_hands_trap-burning-hands-trap-haunt-trigger">Trigger</th><td headers="trap-burning_hands_trap-burning-hands-trap-haunt-trigger">proximity (alarm)</td><th id="trap-burning_hands_trap-burning-hands-trap-haunt-reset">Reset</th><td headers="trap-burning_hands_trap-burning-hands-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> spell effect (<Link to="/spell/burning_hands">burning hands</Link>, 2d4 fire damage, DC 11 Reflex save for half damage); multiple targets (all targets in a 15-ft. cone)</td></tr></tbody></table></ScrollContainer></div></>};
const _clam_clamp = {title: "Clam Clamp", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 173</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-clam_clamp--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Clam Clamp</th></tr><tr><th id="trap-clam_clamp-clam-clamp-haunt-type">Type</th><td headers="trap-clam_clamp-clam-clamp-haunt-type">mechanical</td><th id="trap-clam_clamp-clam-clamp-haunt-cr">CR</th><td headers="trap-clam_clamp-clam-clamp-haunt-cr">2</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any oceans</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>17</td></tr><tr><th id="trap-clam_clamp-clam-clamp-haunt-trigger">Trigger</th><td headers="trap-clam_clamp-clam-clamp-haunt-trigger">location</td><th id="trap-clam_clamp-clam-clamp-haunt-reset">Reset</th><td headers="trap-clam_clamp-clam-clamp-haunt-reset">automatic</td></tr><tr><td colSpan={4}><strong>Effect:</strong> The classic <em>clam clamp</em> trap utilizes the heavy shell of a giant clam, but any similarly large bivalve mollusk or even flotsam can work. A clam clamp is typically set with a lure, such as a piece of shiny treasure. When a creature walks over a clam clamp or attempts to take the treasure, the clamp snaps shut and attempts a grapple with a +15 bonus on the combat maneuver check. The weight of the clam clamp is enough to hold a creature in place until the grappled creature can escape. A clam clamp located in an underwater area is more difficult to craft but also more dangerous to air-breathing creatures due to the fact that it can hold a creature underwater until it drowns; an underwater clam clamp's CR is 5.</td></tr></tbody></table></ScrollContainer></div></>};
const _javelin_trap = {title: "Javelin Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-javelin_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Javelin Trap</th></tr><tr><th id="trap-javelin_trap-javelin-trap-haunt-type">Type</th><td headers="trap-javelin_trap-javelin-trap-haunt-type">mechanical</td><th id="trap-javelin_trap-javelin-trap-haunt-cr">CR</th><td headers="trap-javelin_trap-javelin-trap-haunt-cr">2</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-javelin_trap-javelin-trap-haunt-trigger">Trigger</th><td headers="trap-javelin_trap-javelin-trap-haunt-trigger">location</td><th id="trap-javelin_trap-javelin-trap-haunt-reset">Reset</th><td headers="trap-javelin_trap-javelin-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +15 ranged (1d6+6)</td></tr></tbody></table></ScrollContainer></div></>};
const _spiked_pit_trap = {title: "Spiked Pit Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-spiked_pit_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Spiked Pit Trap</th></tr><tr><th id="trap-spiked_pit_trap-spiked-pit-trap-haunt-type">Type</th><td headers="trap-spiked_pit_trap-spiked-pit-trap-haunt-type">mechanical</td><th id="trap-spiked_pit_trap-spiked-pit-trap-haunt-cr">CR</th><td headers="trap-spiked_pit_trap-spiked-pit-trap-haunt-cr">2</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-spiked_pit_trap-spiked-pit-trap-haunt-trigger">Trigger</th><td headers="trap-spiked_pit_trap-spiked-pit-trap-haunt-trigger">location</td><th id="trap-spiked_pit_trap-spiked-pit-trap-haunt-reset">Reset</th><td headers="trap-spiked_pit_trap-spiked-pit-trap-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> 10-ft.-deep pit (1d6 falling damage); pit spikes (Atk +10 melee, 1d4 spikes per target for 1d4+2 damage each); DC 20 Reflex avoids; multiple targets (all targets in a 10-ft.-square area)</td></tr></tbody></table></ScrollContainer></div></>};
