const _razor_grass = {title: "Razor Grass", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 173</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-razor_grass--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Razor Grass</th></tr><tr><th id="trap-razor_grass-razor-grass-haunt-type">Type</th><td headers="trap-razor_grass-razor-grass-haunt-type">mechanical</td><th id="trap-razor_grass-razor-grass-haunt-cr">CR</th><td headers="trap-razor_grass-razor-grass-haunt-cr">3</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any with undergrowth</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>25</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-razor_grass-razor-grass-haunt-trigger">Trigger</th><td headers="trap-razor_grass-razor-grass-haunt-trigger">location</td><th id="trap-razor_grass-razor-grass-haunt-reset">Reset</th><td headers="trap-razor_grass-razor-grass-haunt-reset">automatic</td></tr><tr><td colSpan={4}><strong>Effect:</strong> By hiding lengths of sharpened sticks or bones amid undergrowth (traditionally tall grass; when used in coastal or underwater areas, this trap is instead called a razor kelp trap), the trapper can lay a simple but effective trap. Whenever a creature moves into a square that contains razor grass, it takes 1d6 points of damage and must succeed at a DC 20 Reflex save or its speed is halved for 24 hours or until it receives magical healing or benefits from a successful DC 15 Heal check.</td></tr></tbody></table></ScrollContainer></div></>};
const _breakaway_log = {title: "Breakaway Log", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 173</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-breakaway_log--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Breakaway Log</th></tr><tr><th id="trap-breakaway_log-breakaway-log-haunt-type">Type</th><td headers="trap-breakaway_log-breakaway-log-haunt-type">mechanical</td><th id="trap-breakaway_log-breakaway-log-haunt-cr">CR</th><td headers="trap-breakaway_log-breakaway-log-haunt-cr">4</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests, jungles, or swamps</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>25</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>30</td></tr><tr><th id="trap-breakaway_log-breakaway-log-haunt-trigger">Trigger</th><td headers="trap-breakaway_log-breakaway-log-haunt-trigger">location</td><th id="trap-breakaway_log-breakaway-log-haunt-reset">Reset</th><td headers="trap-breakaway_log-breakaway-log-haunt-reset">repair</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Fallen trees often form excellent natural bridges over rivers or chasms, or they afford routes to climb more safely over a wall or other barrier. Breakaway logs have been sabotaged so that they collapse once they are used. At the end of a round when a Medium or larger (or two Small) creatures use the log, it collapses. All creatures on the log then fall, taking appropriate damage from the plunge. This example breakaway log fills an area that is 5 feet wide and 20 feet long, and it results in a 20-foot fall which deals 2d6 points of falling damage. A creature that succeeds at a DC 15 Reflex save can cling to the log or leap to safety and avoid the damage entirely.</td></tr></tbody></table></ScrollContainer></div></>};
const _electricity_arc_trap = {title: "Electricity Arc Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-electricity_arc_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Electricity Arc Trap</th></tr><tr><th id="trap-electricity_arc_trap-electricity-arc-trap-haunt-type">Type</th><td headers="trap-electricity_arc_trap-electricity-arc-trap-haunt-type">mechanical</td><th id="trap-electricity_arc_trap-electricity-arc-trap-haunt-cr">CR</th><td headers="trap-electricity_arc_trap-electricity-arc-trap-haunt-cr">4</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>25</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-electricity_arc_trap-electricity-arc-trap-haunt-trigger">Trigger</th><td headers="trap-electricity_arc_trap-electricity-arc-trap-haunt-trigger">touch</td><th id="trap-electricity_arc_trap-electricity-arc-trap-haunt-reset">Reset</th><td headers="trap-electricity_arc_trap-electricity-arc-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> electricity arc (4d6 electricity damage, DC 20 Reflex save for half damage); multiple targets (all targets in a 30-ft. line)</td></tr></tbody></table></ScrollContainer></div></>};
const _spring_arm_spike = {title: "Spring-arm Spike", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 173</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-spring_arm_spike--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Spring-arm Spike</th></tr><tr><th id="trap-spring_arm_spike-spring-arm-spike-haunt-type">Type</th><td headers="trap-spring_arm_spike-spring-arm-spike-haunt-type">mechanical</td><th id="trap-spring_arm_spike-spring-arm-spike-haunt-cr">CR</th><td headers="trap-spring_arm_spike-spring-arm-spike-haunt-cr">4</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests, jungles, or swamps</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-spring_arm_spike-spring-arm-spike-haunt-trigger">Trigger</th><td headers="trap-spring_arm_spike-spring-arm-spike-haunt-trigger">location</td><th id="trap-spring_arm_spike-spring-arm-spike-haunt-reset">Reset</th><td headers="trap-spring_arm_spike-spring-arm-spike-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A spring-arm spike is similar to a <Link to="/trap/spring_snare">spring snare trap</Link> in that it incorporates a strong sapling bent into a taut arc. When a creature enters a square that contains the spring-arm spike's trigger, the sapling snaps forward, driving a pointed spear into the target. The spring-arm spike makes a melee attack +15 (2d10+4/&times;3) against the target, which is also knocked prone unless it succeeds at a DC 20 Reflex save.</td></tr></tbody></table></ScrollContainer></div></>};
const _wall_scythe_trap = {title: "Wall Scythe Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-wall_scythe_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Wall Scythe Trap</th></tr><tr><th id="trap-wall_scythe_trap-wall-scythe-trap-haunt-type">Type</th><td headers="trap-wall_scythe_trap-wall-scythe-trap-haunt-type">mechanical</td><th id="trap-wall_scythe_trap-wall-scythe-trap-haunt-cr">CR</th><td headers="trap-wall_scythe_trap-wall-scythe-trap-haunt-cr">4</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-wall_scythe_trap-wall-scythe-trap-haunt-trigger">Trigger</th><td headers="trap-wall_scythe_trap-wall-scythe-trap-haunt-trigger">location</td><th id="trap-wall_scythe_trap-wall-scythe-trap-haunt-reset">Reset</th><td headers="trap-wall_scythe_trap-wall-scythe-trap-haunt-reset">automatic</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +20 melee (2d4+6/&times;4)</td></tr></tbody></table></ScrollContainer></div></>};
const _deadfall = {title: "Deadfall", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 173</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-deadfall--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={7} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Deadfall</th></tr><tr><th id="trap-deadfall-deadfall-haunt-type">Type</th><td headers="trap-deadfall-deadfall-haunt-type">mechanical</td><th id="trap-deadfall-deadfall-haunt-cr">CR</th><td headers="trap-deadfall-deadfall-haunt-cr">5</td></tr><tr><th scope="row">Terrain</th><td colSpan={3}>any forests, jungles, mountains, or swaps</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-deadfall-deadfall-haunt-trigger">Trigger</th><td headers="trap-deadfall-deadfall-haunt-trigger">location</td><th id="trap-deadfall-deadfall-haunt-reset">Reset</th><td headers="trap-deadfall-deadfall-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Rigged to boulders, logs, or other heavy weights in canopies or on ledges, a trip line strung across an area can create a deadly trap. When a creature enters the deadfall's trigger square, the weights drop in a 20-foot line or a 10-foot-square area, affecting four 5-foot squares in all. Each creature in this area takes 4d6 points of damage and is knocked prone. With a successful DC 20 Reflex save, a target takes half the damage and avoids being knocked prone.</td></tr></tbody></table></ScrollContainer></div></>};
const _falling_block_trap = {title: "Falling Block Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 420</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-falling_block_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Falling Block Trap</th></tr><tr><th id="trap-falling_block_trap-falling-block-trap-haunt-type">Type</th><td headers="trap-falling_block_trap-falling-block-trap-haunt-type">mechanical</td><th id="trap-falling_block_trap-falling-block-trap-haunt-cr">CR</th><td headers="trap-falling_block_trap-falling-block-trap-haunt-cr">5</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>20</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>20</td></tr><tr><th id="trap-falling_block_trap-falling-block-trap-haunt-trigger">Trigger</th><td headers="trap-falling_block_trap-falling-block-trap-haunt-trigger">location</td><th id="trap-falling_block_trap-falling-block-trap-haunt-reset">Reset</th><td headers="trap-falling_block_trap-falling-block-trap-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> Atk +15 melee (6d6); multiple targets (all targets in a 10-ft. square)</td></tr></tbody></table></ScrollContainer></div></>};
const _fireball_trap = {title: "Fireball Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 421</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-fireball_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Fireball Trap</th></tr><tr><th id="trap-fireball_trap-fireball-trap-haunt-type">Type</th><td headers="trap-fireball_trap-fireball-trap-haunt-type">magic</td><th id="trap-fireball_trap-fireball-trap-haunt-cr">CR</th><td headers="trap-fireball_trap-fireball-trap-haunt-cr">5</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>28</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>28</td></tr><tr><th id="trap-fireball_trap-fireball-trap-haunt-trigger">Trigger</th><td headers="trap-fireball_trap-fireball-trap-haunt-trigger">proximity (alarm)</td><th id="trap-fireball_trap-fireball-trap-haunt-reset">Reset</th><td headers="trap-fireball_trap-fireball-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> spell effect (<Link to="/spell/fireball">fireball</Link>, 6d6 fire damage, DC 14 Reflex save for half damage); multiple targets (all targets in a 20-ft.-radius burst)</td></tr></tbody></table></ScrollContainer></div></>};
