const _cone_of_cold_trap = {title: "Cone of Cold Trap", jsx: <><p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 421</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-cone_of_cold_trap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Cone of Cold Trap</th></tr><tr><th id="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-type">Type</th><td headers="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-type">magic</td><th id="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-cr">CR</th><td headers="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-cr">11</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>30</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>30</td></tr><tr><th id="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-trigger">Trigger</th><td headers="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-trigger">proximity (alarm)</td><th id="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-reset">Reset</th><td headers="trap-cone_of_cold_trap-cone-of-cold-trap-haunt-reset">none</td></tr><tr><td colSpan={4}><strong>Effect:</strong> spell effect (<Link to="/spell/cone_of_cold">cone of cold</Link>, 15d6 cold damage, DC 17 Reflex save for half damage); multiple targets (all targets in a 60-ft. cone)</td></tr></tbody></table></ScrollContainer></div></>};
const _crushing_cage_tarp = {title: "Crushing Cage Tarp", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 161</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="trap-crushing_cage_tarp--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={6} to="/rule/elements_of_a_trap"><IonIcon aria-label="Trap" icon="/icons/wolf-trap.svg" /></ThLink><th colSpan={4} scope="col" className="title">Crushing Cage Tarp</th></tr><tr><th id="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-type">Type</th><td headers="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-type">mechanical</td><th id="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-cr">CR</th><td headers="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-cr">11</td></tr><tr><th scope="row" colSpan={2}>Perception DC</th><td colSpan={2}>29</td></tr><tr><th scope="row" colSpan={2}>Disable Device DC</th><td colSpan={2}>30</td></tr><tr><th id="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-trigger">Trigger</th><td headers="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-trigger">location</td><th id="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-reset">Reset</th><td headers="trap-crushing_cage_tarp-crushing-cage-tarp-haunt-reset">manual</td></tr><tr><td colSpan={4}><strong>Effect:</strong> A metal cage drops to seal creatures in a 10-foot-square area (no saving throw), and the ceiling of this cage begins to slowly lower to crush those within it, descending at a rate of 1 foot per round from a height of 10 feet. Creatures inside and outside the trapped area can attempt to open the cage's single locked door (Disable Device DC 30), but the lock is electrified, automatically dealing 6d6 points of electricity damage with each attempt, and imposing a -1 penalty on the check for every 5 points of damage dealt in this way. Creatures inside the cage can attempt to hold up the ceiling of the cage as a ful l-round action with a successful DC 25 Strength check. Success prevents the cage from lowering that round, though it doesn't reverse the progress or allow egress. Once the height of the cage's ceiling is 3 feet, Medium creatures take 10d10 points of bludgeoning damage each round the cage's ceiling is not successfully held up. Once the height of the cage's ceiling is 1 foot, Small creatures take 10d10 points of bludgeoning damage each round that the ceiling is not successfully held up. Tiny creatures can attempt a DC 30 Escape Artist check to flee through the holes in the cage, Diminutive creatures must succeed at a DC 20 Escape Artist check, and Fine creatures can leave automatically. These traps are often employed in conjunction with an effect that prevents dimensional travel, such as <Link to="/spell/dimensional_lock">dimensional lock</Link>. This addition doesn't change the trap's CR, but it does make the trap a combination of mechanical and magical.</td></tr></tbody></table></ScrollContainer></div></>};
